<span class="line"><span style="color:#BABED8;">    </span><span style="color:#676E95;font-style:italic;">#proxy_cache_path /var/tmp/nginx/proxy_cache levels=1:2 keys_zone=cache_one:512m inactive=10m max_size=64m;</span></span>
